    def __init__(self, number, total):
        self.number = number
        self.total = total

    def line(self):
        return f"{self.number}: ${self.total}"

def order_summary(orders):
    lines = []
    for order in orders:
        lines.append(order.line())
    lines.append(f"Total: ${sum(order.total for order in orders)}")
    return "\n".join(lines)

